    public function getSourceContext()
    {
        return new Source("{% extends 'base.html.twig' %}

{% block title 'Contact' %}

{% block body %}
    <div class=\"contact\">
        <div class=\"form\">
            {% for message in app.flashes('success') %}
                <div class=\"success\">
                    {{ message }}
                </div>
            {% endfor %}
            <div class=\"contact--flex\">
                <div class=\"contact__img\">
                    <img src=\"{{ asset(\"/build/images/contact.webp\") }}\" alt=\"image burger contact\">
                </div>
                <div class=\"contact__form\">
                    {{ form_start(form) }}
                    <div class=\"row\">
                        <div class=\"col-2 contact-fn\">
                            {{ form_row(form.firstname) }}
                        </div>
                        <div class=\"col-2\">
                            {{ form_row(form.lastname) }}
                        </div>
                    </div>
                    <div class=\"row\">
                        <div class=\"col-4\">
                            {{ form_row(form.email) }}
                        </div>
                    </div>
                    {{ form_rest(form) }}
                    <div class=\"form-group\">
                        <button class=\"myButton3\">Envoyer</button>
                    </div>
                    {{ form_end(form) }}
                </div>
            </div>
        </div>
    </div>
{% endblock %}", "contact/index.html.twig", "/var/www/html/foodtruck/templates/contact/index.html.twig");
    }
